// App.js — Skin Analysis — Lenient Face+Angle Detection
import React, { useState, useRef, useEffect, useCallback } from 'react';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

/* ═══════════════════════════════════════════════════════════════════════════
   FACE DETECTION — LENIENT
   - Primary: native FaceDetector (Chrome/Edge)
   - Fallback: center-region skin-tone analysis
   - Head angle: estimated from face center offset (very lenient)
   ═══════════════════════════════════════════════════════════════════════════ */
function useFaceDetection(videoRef, isActive) {
  const [hasFace, setHasFace] = useState(false);
  const [facePos, setFacePos] = useState('none');
  const [faceBox, setFaceBox] = useState(null);
  const [headAngle, setHeadAngle] = useState('center');
  const detRef = useRef(null);
  const nativeAvailable = useRef(false);

  useEffect(() => {
    if (!isActive) { setHasFace(false); setFacePos('none'); return; }

    if (window.FaceDetector) {
      try {
        detRef.current = new window.FaceDetector({ fastMode: true, maxDetectedFaces: 1 });
        nativeAvailable.current = true;
      } catch (e) { detRef.current = null; nativeAvailable.current = false; }
    }

    const detect = async () => {
      const v = videoRef.current;
      if (!v || v.readyState !== 4) return;

      try {
        if (detRef.current && nativeAvailable.current) {
          const faces = await detRef.current.detect(v);
          if (faces.length > 0) {
            const f = faces[0].boundingBox;
            const vw = v.videoWidth, vh = v.videoHeight;
            const cx = (f.x + f.width / 2) / vw;
            const cy = (f.y + f.height / 2) / vh;
            const ratio = f.width / vw;

            setHasFace(true);
            setFaceBox({ cx, cy, ratio });

            // Position — very lenient
            if (ratio > 0.65) setFacePos('too-close');
            else if (ratio < 0.08) setFacePos('too-far');
            else setFacePos('centered');

            // Head angle — LENIENT thresholds
            // Video is mirrored, so when user turns left, cx shifts right
            if (cx < 0.32) setHeadAngle('turned-right');
            else if (cx > 0.68) setHeadAngle('turned-left');
            else if (cx < 0.42) setHeadAngle('slight-right');
            else if (cx > 0.58) setHeadAngle('slight-left');
            else setHeadAngle('center');

          } else {
            setHasFace(false); setFacePos('none'); setFaceBox(null); setHeadAngle('center');
          }
        } else {
          // Fallback: skin tone detection — just checks if a face-like region exists
          const c = document.createElement('canvas');
          c.width = 120; c.height = 90;
          const ctx = c.getContext('2d');
          ctx.drawImage(v, 0, 0, 120, 90);
          const d = ctx.getImageData(20, 10, 80, 70);
          let skin = 0;
          for (let i = 0; i < d.data.length; i += 16) { // sample every 4th pixel for speed
            const r = d.data[i], g = d.data[i + 1], b = d.data[i + 2];
            if (r > 50 && g > 25 && b > 10 && r > g && (r - b) > 8) skin++;
          }
          const skinRatio = skin / (d.data.length / 16);
          const detected = skinRatio > 0.08; // very lenient

          setHasFace(detected);
          setFacePos(detected ? 'centered' : 'none');
          setFaceBox(detected ? { cx: 0.5, cy: 0.45, ratio: 0.3 } : null);

          // Fallback can't reliably detect angle, so we'll be permissive
          // Check left/right bias in skin distribution
          if (detected) {
            const leftD = ctx.getImageData(10, 15, 40, 60);
            const rightD = ctx.getImageData(70, 15, 40, 60);
            let leftSkin = 0, rightSkin = 0;
            for (let i = 0; i < leftD.data.length; i += 16) {
              const r = leftD.data[i], g = leftD.data[i+1], b = leftD.data[i+2];
              if (r > 50 && g > 25 && r > g) leftSkin++;
            }
            for (let i = 0; i < rightD.data.length; i += 16) {
              const r = rightD.data[i], g = rightD.data[i+1], b = rightD.data[i+2];
              if (r > 50 && g > 25 && r > g) rightSkin++;
            }
            const total = leftSkin + rightSkin || 1;
            const leftPct = leftSkin / total;
            // With mirrored video, more skin on left side = user turned right
            if (leftPct > 0.62) setHeadAngle('slight-right');
            else if (leftPct < 0.38) setHeadAngle('slight-left');
            else setHeadAngle('center');
          } else {
            setHeadAngle('center');
          }
        }
      } catch (e) { /* silently ignore */ }
    };

    const interval = setInterval(detect, 400);
    return () => clearInterval(interval);
  }, [isActive, videoRef]);

  return { hasFace, facePos, faceBox, headAngle };
}

/* ═══════════════════════════════════════════════════════════════════════════
   FACE GUIDE OVERLAY
   ═══════════════════════════════════════════════════════════════════════════ */
function FaceGuide({ hasFace, facePos, targetAngle, faceBox, headAngle, canCapture }) {

  const color = !hasFace ? '#ef4444' : canCapture ? '#22c55e' : '#f59e0b';

  const getMessage = () => {
    if (!hasFace) return { icon: '👤', text: 'Position your face in the frame' };
    if (facePos === 'too-close') return { icon: '↔', text: 'Move back a little' };
    if (facePos === 'too-far') return { icon: '↔', text: 'Come closer' };

    if (canCapture) return { icon: '✓', text: 'Ready! Tap capture' };

    if (targetAngle === 'front') return { icon: '👤', text: 'Face the camera directly' };
    if (targetAngle === 'left') return { icon: '↩', text: 'Turn your head to the LEFT' };
    if (targetAngle === 'right') return { icon: '↪', text: 'Turn your head to the RIGHT' };
    return { icon: '⚠', text: 'Adjust position' };
  };

  const msg = getMessage();
  const ox = faceBox ? (faceBox.cx - 0.5) * 35 : 0;
  const oy = faceBox ? (faceBox.cy - 0.45) * 25 : 0;
  const sc = faceBox ? Math.min(Math.max(faceBox.ratio / 0.28, 0.8), 1.25) : 1;

  return (
    <div className="face-guide">
      <svg viewBox="0 0 300 380" className={`guide-svg ${canCapture ? 'ready' : ''}`}
        style={{ transform: `translate(${ox}px, ${oy}px) scale(${sc})`, transition: 'transform 0.25s ease-out' }}>
        <defs>
          <filter id="gl"><feGaussianBlur stdDeviation="3" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
        </defs>

        <ellipse cx="150" cy="155" rx="78" ry="102" fill="none" stroke={color}
          strokeWidth={canCapture ? 3 : 1.8} strokeDasharray={canCapture ? 'none' : '10,7'}
          opacity={canCapture ? 1 : 0.45} filter={canCapture ? 'url(#gl)' : 'none'}
          style={{ transition: 'all 0.35s ease' }} />

        {targetAngle === 'front' && (
          <g opacity="0.15" stroke={color} strokeWidth="0.7">
            <line x1="150" y1="70" x2="150" y2="240"/>
            <line x1="78" y1="155" x2="222" y2="155"/>
          </g>
        )}
        {targetAngle === 'left' && (
          <g opacity={canCapture ? 0.9 : 0.5}>
            <path d="M 82 105 Q 52 155 82 210" fill="none" stroke={color} strokeWidth="2.5" strokeDasharray={canCapture ? 'none' : '5,4'}/>
            <polygon points="77,103 87,103 82,90" fill={color}/>
            <text x="36" y="162" fill={color} fontSize="16" fontWeight="700">45°</text>
          </g>
        )}
        {targetAngle === 'right' && (
          <g opacity={canCapture ? 0.9 : 0.5}>
            <path d="M 218 105 Q 248 155 218 210" fill="none" stroke={color} strokeWidth="2.5" strokeDasharray={canCapture ? 'none' : '5,4'}/>
            <polygon points="213,103 223,103 218,90" fill={color}/>
            <text x="245" y="162" fill={color} fontSize="16" fontWeight="700">45°</text>
          </g>
        )}

        {canCapture && (
          <ellipse cx="150" cy="155" rx="88" ry="112" fill="none" stroke={color} strokeWidth="1" opacity="0.35">
            <animate attributeName="rx" values="86;93;86" dur="2.2s" repeatCount="indefinite"/>
            <animate attributeName="ry" values="110;117;110" dur="2.2s" repeatCount="indefinite"/>
            <animate attributeName="opacity" values="0.35;0.08;0.35" dur="2.2s" repeatCount="indefinite"/>
          </ellipse>
        )}
      </svg>

      <div className={`guide-msg ${canCapture ? 'ok' : !hasFace ? 'err' : 'warn'}`}>
        <span className="guide-msg-icon">{msg.icon}</span>
        <span>{msg.text}</span>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   MAIN APP
   ═══════════════════════════════════════════════════════════════════════════ */
function App() {
  const [step, setStep] = useState('intro');
  const [images, setImages] = useState({});
  const [curAngle, setCurAngle] = useState('front');
  const [stream, setStream] = useState(null);
  const [quality, setQuality] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [error, setError] = useState(null);
  const [camReady, setCamReady] = useState(false);
  const [aStep, setAStep] = useState(0);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [overrideReady, setOverrideReady] = useState(false);
  const overrideTimerRef = useRef(null);

  const vidRef = useRef(null);
  const canRef = useRef(null);
  const stmRef = useRef(null);

  const { hasFace, facePos, faceBox, headAngle } = useFaceDetection(vidRef, step === 'capture' && camReady);

  const angles = [
    { id: 'front', label: 'Front', desc: 'Look directly at camera', icon: '🧑' },
    { id: 'left', label: 'Left 45°', desc: 'Turn head 45° to the left', icon: '👤 ↰' },
    { id: 'right', label: 'Right 45°', desc: 'Turn head 45° to the right', icon: '↱ 👤' }
  ];

  /* ── Angle validation — LENIENT ──
     Front: center or slight-left or slight-right (just facing roughly forward)
     Left: turned-left, slight-left, OR center (we accept center because detection is imperfect)
     Right: turned-right, slight-right, OR center
     The key gating is: face MUST be detected. Angle is soft guidance. */
  const isAngleOk = () => {
    if (!hasFace) return false;
    if (facePos === 'too-close' || facePos === 'too-far') return false;

    if (curAngle === 'front') {
      return headAngle === 'center' || headAngle === 'slight-left' || headAngle === 'slight-right';
    }
    if (curAngle === 'left') {
      // Accept any leftward indication OR center (fallback can't detect angle well)
      return headAngle === 'turned-left' || headAngle === 'slight-left' || headAngle === 'center';
    }
    if (curAngle === 'right') {
      return headAngle === 'turned-right' || headAngle === 'slight-right' || headAngle === 'center';
    }
    return false;
  };

  // canCapture: face detected AND (angle ok OR override timer elapsed)
  const canCapture = camReady && hasFace && facePos !== 'too-close' && facePos !== 'too-far' && (isAngleOk() || overrideReady);

  /* ── Override timer: if face is detected but angle isn't "perfect" for 4 seconds,
       auto-enable capture anyway. This prevents users from being stuck. ── */
  useEffect(() => {
    // Reset override when angle changes or face lost
    setOverrideReady(false);
    if (overrideTimerRef.current) clearTimeout(overrideTimerRef.current);

    if (hasFace && facePos !== 'too-close' && facePos !== 'too-far' && !isAngleOk()) {
      // Face is there but angle isn't matching — start override countdown
      overrideTimerRef.current = setTimeout(() => {
        setOverrideReady(true);
      }, 4000); // 4 seconds then allow capture anyway
    }

    return () => { if (overrideTimerRef.current) clearTimeout(overrideTimerRef.current); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [hasFace, facePos, headAngle, curAngle]);

  // Reset override when angle step changes
  useEffect(() => {
    setOverrideReady(false);
  }, [curAngle]);

  useEffect(() => { return () => { if (stmRef.current) stmRef.current.getTracks().forEach(t => t.stop()); }; }, []);

  const startCamera = async () => {
    try {
      if (stmRef.current) stmRef.current.getTracks().forEach(t => t.stop());
      setCamReady(false); setError(null);
      const ms = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 1280, min: 480 }, height: { ideal: 720, min: 360 }, facingMode: 'user' }
      });
      stmRef.current = ms; setStream(ms); setStep('capture');
      setTimeout(() => {
        if (vidRef.current) {
          vidRef.current.srcObject = ms;
          vidRef.current.onloadedmetadata = () => vidRef.current.play().then(() => setCamReady(true)).catch(() => setError('Video failed'));
        }
      }, 120);
    } catch (e) {
      setError(e.name === 'NotAllowedError' ? 'Camera access denied.' : e.name === 'NotFoundError' ? 'No camera found.' : `Camera error: ${e.message}`);
    }
  };

  useEffect(() => {
    if (step === 'capture' && vidRef.current && stmRef.current && !vidRef.current.srcObject) {
      vidRef.current.srcObject = stmRef.current;
      vidRef.current.onloadedmetadata = () => vidRef.current.play().then(() => setCamReady(true)).catch(console.error);
    }
  }, [step]);

  const stopCam = useCallback(() => {
    if (stmRef.current) { stmRef.current.getTracks().forEach(t => t.stop()); stmRef.current = null; }
    if (vidRef.current) vidRef.current.srcObject = null;
    setStream(null); setCamReady(false);
  }, []);

  // Quality check
  useEffect(() => {
    if (step !== 'capture' || !camReady) return;
    const iv = setInterval(async () => {
      try {
        const c = canRef.current, v = vidRef.current;
        if (!c || !v || v.readyState !== 4) return;
        c.width = v.videoWidth; c.height = v.videoHeight;
        c.getContext('2d').drawImage(v, 0, 0);
        const blob = await new Promise(r => c.toBlob(r, 'image/jpeg', 0.5));
        if (!blob) return;
        const fd = new FormData(); fd.append('image', new File([blob], 'q.jpg', { type: 'image/jpeg' }));
        const res = await fetch(`${API_URL}/api/check-quality`, { method: 'POST', body: fd });
        if (res.ok) setQuality(await res.json());
      } catch (e) { }
    }, 3500);
    return () => clearInterval(iv);
  }, [step, camReady]);

  const capture = () => {
    if (!canCapture) return;
    const c = canRef.current, v = vidRef.current;
    if (!c || !v || v.readyState !== 4) return;
    c.width = v.videoWidth; c.height = v.videoHeight;
    c.getContext('2d').drawImage(v, 0, 0);
    const url = c.toDataURL('image/jpeg', 0.95);
    const next = { ...images, [curAngle]: url };
    setImages(next);
    setOverrideReady(false);
    const idx = angles.findIndex(a => a.id === curAngle);
    if (idx < angles.length - 1) setCurAngle(angles[idx + 1].id);
    else { stopCam(); analyze(next); }
  };

  const retake = (id) => { setImages(p => { const n = { ...p }; delete n[id]; return n; }); setCurAngle(id); };

  const analyze = async (imgs) => {
    const src = imgs || images;
    setStep('analyzing'); setError(null); setAStep(0);
    const t1 = setTimeout(() => setAStep(1), 1200);
    const t2 = setTimeout(() => setAStep(2), 3500);
    try {
      if (!src.front) throw new Error('Front view required');
      const b = atob(src.front.split(',')[1]);
      const a = new Uint8Array(b.length);
      for (let i = 0; i < b.length; i++) a[i] = b.charCodeAt(i);
      const fd = new FormData();
      fd.append('image', new File([a], 'skin.jpg', { type: 'image/jpeg' }));
      const res = await fetch(`${API_URL}/api/analyze`, { method: 'POST', body: fd });
      if (!res.ok) { const e = await res.json(); throw new Error(e.error || 'Analysis failed'); }
      const data = await res.json();
      setAnalysis({ ...data.analysis, _images: src });
      setStep('results');
    } catch (e) { setError(e.message); setStep('intro'); }
    finally { clearTimeout(t1); clearTimeout(t2); }
  };

  const downloadPdf = async () => {
    setPdfLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/generate-report`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ analysis, images: analysis._images, date: new Date().toISOString() })
      });
      if (!res.ok) throw new Error('PDF generation failed');
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url; link.download = `Skin_Report_${new Date().toISOString().split('T')[0]}.pdf`;
      link.click(); URL.revokeObjectURL(url);
    } catch (e) { setError('PDF: ' + e.message); }
    finally { setPdfLoading(false); }
  };

  const reset = () => {
    stopCam(); setImages({}); setCurAngle('front');
    setAnalysis(null); setError(null); setQuality(null); setCamReady(false); setStep('intro'); setOverrideReady(false);
  };

  const cur = angles.find(a => a.id === curAngle);

  // Capture button label
  const getShutterLabel = () => {
    if (!camReady) return 'Starting…';
    if (!hasFace) return 'No face detected';
    if (facePos === 'too-close') return 'Move back';
    if (facePos === 'too-far') return 'Come closer';
    if (canCapture) return '📸 Capture';
    // Face is there but angle not matched yet — show encouraging message
    if (curAngle === 'left') return 'Turn head left…';
    if (curAngle === 'right') return 'Turn head right…';
    return 'Face the camera…';
  };

  return (
    <div className="app">

      {/* ─── INTRO ─── */}
      {step === 'intro' && (
        <div className="screen intro">
          <div className="intro-card">
            <span className="badge">DERMA · AI</span>
            <h1>Skin Analysis</h1>
            <p className="tagline">Clinical-grade AI skin assessment with personalized treatment plan</p>

            <div className="feat-row">
              {[
                { i: '🔬', t: 'Face Detection', d: 'Validates face presence before each capture' },
                { i: '📐', t: '3-Angle Scan', d: 'Front, left 45° and right 45° for coverage' },
                { i: '📋', t: 'Doctor Report', d: 'Professional PDF you can share with a dermatologist' }
              ].map((f, i) => (
                <div className="feat" key={i}>
                  <span className="feat-i">{f.i}</span>
                  <strong>{f.t}</strong>
                  <span>{f.d}</span>
                </div>
              ))}
            </div>

            <button className="btn-go" onClick={startCamera}>
              Begin Analysis
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>

            <div className="prep">
              <span className="prep-tag">Preparation</span>
              <div className="prep-items">
                {['☀️ Good lighting', '🧼 Clean face', '😐 Neutral expression', '📱 Steady hands'].map((t, i) => (
                  <span key={i} className="prep-item">{t}</span>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ─── CAPTURE ─── */}
      {step === 'capture' && (
        <div className="screen capture">
          <header className="cap-head">
            <button className="btn-back" onClick={() => { stopCam(); reset(); }}>← Back</button>
            <div className="cap-steps">
              {angles.map(a => (
                <span key={a.id} className={`cap-pill ${images[a.id] ? 'done' : ''} ${curAngle === a.id ? 'cur' : ''}`}>
                  {images[a.id] ? '✓ ' : ''}{a.label}
                </span>
              ))}
            </div>
          </header>

          <div className="cap-body">
            <div className="cam-wrap">
              <video ref={vidRef} autoPlay playsInline muted className="cam-video" />
              <canvas ref={canRef} style={{ display: 'none' }} />

              {!camReady && (
                <div className="cam-loading"><div className="spin" /><p>Initializing camera…</p></div>
              )}

              {camReady && (
                <FaceGuide hasFace={hasFace} facePos={facePos} targetAngle={curAngle} faceBox={faceBox} headAngle={headAngle} canCapture={canCapture} />
              )}

              {quality?.quality?.resolution && (
                <div className="q-tags">
                  <span className={`q-tag ${quality.quality.lighting.isGood ? 'g' : 'w'}`}>
                    {quality.quality.lighting.isGood ? '☀' : '🌑'} Light
                  </span>
                  <span className={`q-tag ${quality.quality.sharpness.isGood ? 'g' : 'w'}`}>
                    {quality.quality.sharpness.isGood ? '✦' : '~'} Focus
                  </span>
                </div>
              )}
            </div>

            <div className="cap-side">
              <div className="angle-info">
                <div className="angle-num">{angles.findIndex(a => a.id === curAngle) + 1}<span>/{angles.length}</span></div>
                <h3>{cur?.label}</h3>
                <p>{cur?.desc}</p>
              </div>

              <button className={`btn-shutter ${canCapture ? 'go' : ''}`} onClick={capture} disabled={!canCapture}>
                <span className="shutter-ring"><span className="shutter-dot" /></span>
                <span className="shutter-label">{getShutterLabel()}</span>
              </button>

              {/* Hint when override is about to kick in */}
              {hasFace && !isAngleOk() && !overrideReady && (
                <p className="override-hint">Hold still… capture will enable in a moment</p>
              )}
              {overrideReady && !isAngleOk() && (
                <p className="override-hint ready">✓ Capture enabled — go ahead!</p>
              )}

              <div className="thumbs">
                {angles.map(a => (
                  <div key={a.id} className={`thumb ${images[a.id] ? 'taken' : ''} ${curAngle === a.id && !images[a.id] ? 'active' : ''}`}>
                    {images[a.id] ? (
                      <>
                        <img src={images[a.id]} alt={a.label} />
                        <button className="thumb-x" onClick={() => retake(a.id)}>↻</button>
                        <span className="thumb-ok">✓</span>
                      </>
                    ) : (
                      <span className="thumb-lbl">{a.label}</span>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ─── ANALYZING ─── */}
      {step === 'analyzing' && (
        <div className="screen analyze">
          <div className="analyze-card">
            {images.front && (
              <div className="scan-avatar">
                <img src={images.front} alt="face" />
                <div className="scan-bar" />
              </div>
            )}
            <h2>Analyzing Your Skin</h2>
            <p className="analyze-sub">AI dermatological assessment in progress</p>
            <div className="analyze-steps">
              {['Verifying image quality', 'Detecting skin conditions', 'Building treatment plan'].map((l, i) => (
                <div key={i} className={`a-step ${aStep >= i ? 'on' : ''} ${aStep > i ? 'done' : ''}`}>
                  <span className="a-dot">{aStep > i ? '✓' : aStep === i ? '◉' : '○'}</span>{l}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ─── RESULTS ─── */}
      {step === 'results' && analysis && (
        <div className="screen results">
          <header className="res-head">
            <div>
              <h1>Dermatological Report</h1>
              <span className="res-date">{new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}</span>
            </div>
            <div className="res-actions">
              <button className="btn-pdf" onClick={downloadPdf} disabled={pdfLoading}>
                {pdfLoading ? '⏳ Generating…' : '📄 Download PDF'}
              </button>
              <button className="btn-again" onClick={reset}>+ New</button>
            </div>
          </header>

          <div className="res-body">
            {analysis._images && (
              <section className="card photos-card">
                <h2>Patient Photos</h2>
                <div className="photo-row">
                  {angles.map(a => analysis._images[a.id] && (
                    <figure key={a.id} className="photo-fig">
                      <img src={analysis._images[a.id]} alt={a.label} />
                      <figcaption>{a.label}</figcaption>
                    </figure>
                  ))}
                </div>
              </section>
            )}

            <section className="card score-card">
              <div className="score-left">
                <h2>Overall Assessment</h2>
                <p className="score-summary">{analysis.summary}</p>
                <div className="score-meta">
                  <span className="meta-chip">Skin Type: <strong>{analysis.skinType}</strong></span>
                </div>
              </div>
              <div className="score-right">
                <div className="score-ring">
                  <svg viewBox="0 0 120 120">
                    <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,0.08)" strokeWidth="10" />
                    <circle cx="60" cy="60" r="50" fill="none"
                      stroke={analysis.overallScore >= 70 ? '#22c55e' : analysis.overallScore >= 40 ? '#f59e0b' : '#ef4444'}
                      strokeWidth="10" strokeLinecap="round"
                      strokeDasharray={`${(analysis.overallScore / 100) * 314} 314`}
                      transform="rotate(-90 60 60)"
                      style={{ transition: 'stroke-dasharray 1.5s ease' }} />
                  </svg>
                  <div className="score-val">{analysis.overallScore}<span>/100</span></div>
                </div>
              </div>
            </section>

            <section className="card">
              <h2>Detected Conditions</h2>
              {analysis.detectedIssues?.length > 0 ? (
                <div className="issues">
                  {analysis.detectedIssues.map((is, i) => (
                    <div key={i} className={`issue sev-${is.severity}`}>
                      <div className="issue-top"><h3>{is.issue}</h3><span className="sev">{is.severity}</span></div>
                      <p>{is.description}</p>
                      {is.affected_areas?.length > 0 && <small className="areas">Areas: {is.affected_areas.join(', ')}</small>}
                    </div>
                  ))}
                </div>
              ) : <p className="empty-msg">✨ No significant conditions found</p>}
            </section>

            {analysis.zoneAnalysis && (
              <section className="card">
                <h2>Zone Analysis</h2>
                <div className="zones">
                  {Object.entries(analysis.zoneAnalysis).map(([z, d]) => (
                    <div key={z} className={`zone c-${d.condition}`}>
                      <div className="zone-head">
                        <span className="zone-name">{z.replace(/([A-Z])/g, ' $1').trim()}</span>
                        <span className="zone-sc">{d.score}/10</span>
                      </div>
                      <span className="zone-cond">{d.condition}</span>
                      {d.issues?.length > 0 && <ul>{d.issues.map((x, i) => <li key={i}>{x}</li>)}</ul>}
                    </div>
                  ))}
                </div>
              </section>
            )}

            {analysis.treatmentRecommendations?.length > 0 && (
              <section className="card">
                <h2>Treatment Plan</h2>
                <div className="treatments">
                  {analysis.treatmentRecommendations.map((t, i) => (
                    <div key={i} className="treat"><h3>{t.treatment}</h3><p>{t.purpose}</p><small>{t.frequency}</small></div>
                  ))}
                </div>
              </section>
            )}

            {analysis.homeCareRoutine && (
              <section className="card">
                <h2>Home Care Routine</h2>
                <div className="routine-cols">
                  <div><h3>☀️ Morning</h3><ol>{analysis.homeCareRoutine.morning.map((s, i) => <li key={i}>{s}</li>)}</ol></div>
                  <div><h3>🌙 Evening</h3><ol>{analysis.homeCareRoutine.evening.map((s, i) => <li key={i}>{s}</li>)}</ol></div>
                </div>
              </section>
            )}

            {analysis.lifestyleSuggestions && (
              <section className="card">
                <h2>Lifestyle Recommendations</h2>
                <div className="life-cols">
                  {Object.entries(analysis.lifestyleSuggestions).map(([c, items]) => (
                    <div key={c}><h3>{c.charAt(0).toUpperCase() + c.slice(1)}</h3><ul>{items.map((s, i) => <li key={i}>{s}</li>)}</ul></div>
                  ))}
                </div>
              </section>
            )}

            {analysis.progressTimeline && (
              <section className="card">
                <h2>Expected Timeline</h2>
                <div className="timeline">
                  {Object.entries(analysis.progressTimeline).map(([p, c]) => (
                    <div key={p} className="tl-item"><div className="tl-dot" /><div><strong>{p.replace(/([A-Z])/g, ' $1').trim()}</strong><p>{c}</p></div></div>
                  ))}
                </div>
              </section>
            )}

            <p className="disclaimer">This AI-generated report is for informational purposes only and does not constitute medical advice. Please consult a board-certified dermatologist for diagnosis and treatment.</p>
          </div>

          <footer className="res-foot">
            <button className="btn-primary" onClick={reset}>New Analysis</button>
            <button className="btn-outline" onClick={downloadPdf} disabled={pdfLoading}>
              {pdfLoading ? 'Generating…' : '📄 Download PDF Report'}
            </button>
          </footer>
        </div>
      )}

      {error && (
        <div className="toast"><span>⚠️ {error}</span><button onClick={() => setError(null)}>✕</button></div>
      )}
    </div>
  );
}

export default App;
